using System.Collections.Concurrent;

namespace sv_492c595e6fb849129c1b400825589742.Services;

public class WizardData
{
    // Step 1: Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = [];

    public int LastCompletedStep { get; set; }
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
}

/// <summary>
/// Singleton service that stores wizard data keyed by session ID.
/// This bridges the static layout and interactive pages — both can
/// access it using the session ID from ASP.NET Core session middleware.
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, WizardData> _store = new();

    public WizardData GetOrCreate(string sessionId)
    {
        return _store.GetOrAdd(sessionId, _ => new WizardData());
    }

    public void Remove(string sessionId)
    {
        _store.TryRemove(sessionId, out _);
    }
}

@using sv_492c595e6fb849129c1b400825589742.Services
@inject WizardStateService WizardState
@inject IHttpContextAccessor HttpContextAccessor

@{
    var sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
    var data = WizardState.GetOrCreate(sessionId);
    var lastCompleted = data.LastCompletedStep;
}

<nav class="wizard-progress mb-4">
    <h6 class="text-muted mb-2">Step @CurrentStep of 4</h6>
    <div class="d-flex gap-2">
        @for (int i = 0; i < Steps.Length; i++)
        {
            var step = Steps[i];
            var stepNum = i + 1;
            var isActive = stepNum == CurrentStep;
            var isCompleted = stepNum <= lastCompleted;
            var cssClass = isActive ? "btn-primary" : isCompleted ? "btn-success" : "btn-outline-secondary";
            <a href="@step.Url" class="btn btn-sm @cssClass">
                @stepNum. @step.Label
            </a>
        }
    </div>
</nav>

@code {
    [Parameter] public int CurrentStep { get; set; }

    private static readonly (string Label, string Url)[] Steps =
    [
        ("Personal Info", "/apply/personal-info"),
        ("Experience", "/apply/experience"),
        ("References", "/apply/references"),
        ("Review", "/apply/review")
    ];
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_492c595e6fb849129c1b400825589742.Services
@inject WizardStateService WizardState
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<WizardProgressBar CurrentStep="1" />

<h1>Personal Information</h1>

<EditForm Model="Model" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Model.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email Address</label>
        <InputText class="form-control" @bind-Value="Model.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next &rarr;</button>
</EditForm>

@code {
    private string _sessionId = string.Empty;
    private PersonalInfoModel Model { get; set; } = new();

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
        var data = WizardState.GetOrCreate(_sessionId);
        Model.Name = data.Name;
        Model.Email = data.Email;
    }

    private void Next()
    {
        var data = WizardState.GetOrCreate(_sessionId);
        data.Name = Model.Name;
        data.Email = Model.Email;
        if (data.LastCompletedStep < 1) data.LastCompletedStep = 1;
        Navigation.NavigateTo("/apply/experience");
    }

    private class PersonalInfoModel
    {
        public string Name { get; set; } = string.Empty;
        public string Email { get; set; } = string.Empty;
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@using sv_492c595e6fb849129c1b400825589742.Services
@inject WizardStateService WizardState
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<WizardProgressBar CurrentStep="2" />

<h1>Work Experience</h1>

@foreach (var (entry, index) in JobEntries.Select((e, i) => (e, i)))
{
    <div class="card mb-3 p-3">
        <div class="row g-2">
            <div class="col-md-4">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="entry.Company" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Job Title</label>
                <input class="form-control" @bind="entry.Title" />
            </div>
            <div class="col-md-3">
                <label class="form-label">Years</label>
                <input class="form-control" @bind="entry.Years" />
            </div>
            <div class="col-md-1 d-flex align-items-end">
                <button class="btn btn-outline-danger btn-sm" @onclick="() => Remove(index)">✕</button>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="Add">+ Add Job</button>

<div class="d-flex gap-2">
    <a href="/apply/personal-info" class="btn btn-secondary">&larr; Back</a>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private string _sessionId = string.Empty;
    private List<JobEntry> JobEntries { get; set; } = [];

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
        var data = WizardState.GetOrCreate(_sessionId);
        // Clone entries so edits don't persist until Save
        JobEntries = data.JobHistory.Select(j => new JobEntry
        {
            Company = j.Company, Title = j.Title, Years = j.Years
        }).ToList();

        if (JobEntries.Count == 0) JobEntries.Add(new JobEntry());
    }

    private void Add() => JobEntries.Add(new JobEntry());
    private void Remove(int index) => JobEntries.RemoveAt(index);

    private void Next()
    {
        var data = WizardState.GetOrCreate(_sessionId);
        data.JobHistory = JobEntries
            .Where(j => !string.IsNullOrWhiteSpace(j.Company))
            .ToList();
        if (data.LastCompletedStep < 2) data.LastCompletedStep = 2;
        Navigation.NavigateTo("/apply/references");
    }
}

