@page "/apply/experience"
@rendermode InteractiveServer
@using sv_492c595e6fb849129c1b400825589742.Services
@inject WizardStateService WizardState
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<WizardProgressBar CurrentStep="2" />

<h1>Work Experience</h1>

@foreach (var (entry, index) in JobEntries.Select((e, i) => (e, i)))
{
    <div class="card mb-3 p-3">
        <div class="row g-2">
            <div class="col-md-4">
                <label class="form-label">Company</label>
                <input class="form-control" @bind="entry.Company" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Job Title</label>
                <input class="form-control" @bind="entry.Title" />
            </div>
            <div class="col-md-3">
                <label class="form-label">Years</label>
                <input class="form-control" @bind="entry.Years" />
            </div>
            <div class="col-md-1 d-flex align-items-end">
                <button class="btn btn-outline-danger btn-sm" @onclick="() => Remove(index)">✕</button>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="Add">+ Add Job</button>

<div class="d-flex gap-2">
    <a href="/apply/personal-info" class="btn btn-secondary">&larr; Back</a>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private string _sessionId = string.Empty;
    private List<JobEntry> JobEntries { get; set; } = [];

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
        var data = WizardState.GetOrCreate(_sessionId);
        // Clone entries so edits don't persist until Save
        JobEntries = data.JobHistory.Select(j => new JobEntry
        {
            Company = j.Company, Title = j.Title, Years = j.Years
        }).ToList();

        if (JobEntries.Count == 0) JobEntries.Add(new JobEntry());
    }

    private void Add() => JobEntries.Add(new JobEntry());
    private void Remove(int index) => JobEntries.RemoveAt(index);

    private void Next()
    {
        var data = WizardState.GetOrCreate(_sessionId);
        data.JobHistory = JobEntries
            .Where(j => !string.IsNullOrWhiteSpace(j.Company))
            .ToList();
        if (data.LastCompletedStep < 2) data.LastCompletedStep = 2;
        Navigation.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@using sv_492c595e6fb849129c1b400825589742.Services
@inject WizardStateService WizardState
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<WizardProgressBar CurrentStep="3" />

<h1>References</h1>

@foreach (var (entry, index) in ReferenceEntries.Select((e, i) => (e, i)))
{
    <div class="card mb-3 p-3">
        <div class="row g-2">
            <div class="col-md-4">
                <label class="form-label">Name</label>
                <input class="form-control" @bind="entry.Name" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Email</label>
                <input class="form-control" @bind="entry.Email" />
            </div>
            <div class="col-md-3">
                <label class="form-label">Relationship</label>
                <input class="form-control" @bind="entry.Relationship" />
            </div>
            <div class="col-md-1 d-flex align-items-end">
                <button class="btn btn-outline-danger btn-sm" @onclick="() => Remove(index)">✕</button>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="Add">+ Add Reference</button>

<div class="d-flex gap-2">
    <a href="/apply/experience" class="btn btn-secondary">&larr; Back</a>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private string _sessionId = string.Empty;
    private List<ReferenceContact> ReferenceEntries { get; set; } = [];

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
        var data = WizardState.GetOrCreate(_sessionId);
        ReferenceEntries = data.References.Select(r => new ReferenceContact
        {
            Name = r.Name, Email = r.Email, Relationship = r.Relationship
        }).ToList();

        if (ReferenceEntries.Count == 0) ReferenceEntries.Add(new ReferenceContact());
    }

    private void Add() => ReferenceEntries.Add(new ReferenceContact());
    private void Remove(int index) => ReferenceEntries.RemoveAt(index);

    private void Next()
    {
        var data = WizardState.GetOrCreate(_sessionId);
        data.References = ReferenceEntries
            .Where(r => !string.IsNullOrWhiteSpace(r.Name))
            .ToList();
        if (data.LastCompletedStep < 3) data.LastCompletedStep = 3;
        Navigation.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@using sv_492c595e6fb849129c1b400825589742.Services
@inject WizardStateService WizardState
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Navigation

<WizardProgressBar CurrentStep="4" />

<h1>Review Your Application</h1>

@if (Data is not null)
{
    <div class="card mb-3 p-3">
        <h5>Personal Information</h5>
        <p><strong>Name:</strong> @Data.Name</p>
        <p><strong>Email:</strong> @Data.Email</p>
        <a href="/apply/personal-info" class="btn btn-sm btn-outline-secondary">Edit</a>
    </div>

    <div class="card mb-3 p-3">
        <h5>Work Experience</h5>
        @if (Data.JobHistory.Count == 0)
        {
            <p class="text-muted">No entries.</p>
        }
        else
        {
            <ul>
                @foreach (var job in Data.JobHistory)
                {
                    <li><strong>@job.Title</strong> at @job.Company (@job.Years)</li>
                }
            </ul>
        }
        <a href="/apply/experience" class="btn btn-sm btn-outline-secondary">Edit</a>
    </div>

    <div class="card mb-3 p-3">
        <h5>References</h5>
        @if (Data.References.Count == 0)
        {
            <p class="text-muted">No entries.</p>
        }
        else
        {
            <ul>
                @foreach (var r in Data.References)
                {
                    <li><strong>@r.Name</strong> — @r.Email (@r.Relationship)</li>
                }
            </ul>
        }
        <a href="/apply/references" class="btn btn-sm btn-outline-secondary">Edit</a>
    </div>

    <div class="d-flex gap-2">
        <a href="/apply/references" class="btn btn-secondary">&larr; Back</a>
        <button class="btn btn-success" @onclick="Submit">Submit Application</button>
    </div>

    @if (_submitted)
    {
        <div class="alert alert-success mt-3">Application submitted successfully!</div>
    }
}

@code {
    private string _sessionId = string.Empty;
    private WizardData? Data;
    private bool _submitted;

    protected override void OnInitialized()
    {
        _sessionId = HttpContextAccessor.HttpContext?.Session.Id ?? "";
        Data = WizardState.GetOrCreate(_sessionId);
    }

    private void Submit()
    {
        // In a real app, persist to a database here.
        _submitted = true;
        var data = WizardState.GetOrCreate(_sessionId);
        data.LastCompletedStep = 4;
    }
}

